import React from 'react';

const PALETTE = ['#2563eb', '#16a34a', '#d97706', '#dc2626', '#7c3aed', '#0891b2'];

function colorFor(name) {
  let h = 0;
  for (let i = 0; i < name.length; i++) h = (h * 31 + name.charCodeAt(i)) >>> 0;
  return PALETTE[h % PALETTE.length];
}

function initials(name) {
  return name
    .split(' ')
    .map((w) => w[0])
    .slice(0, 2)
    .join('')
    .toUpperCase();
}

const bubble = {
  width: 40,
  height: 40,
  borderRadius: '50%',
  border: '2px solid #fff',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  color: '#fff',
  fontSize: 14,
  fontWeight: 600,
  boxSizing: 'border-box',
};

export default function AvatarGroup({ users, max = 4 }) {
  const visible = users.slice(0, max);
  const overflow = Math.max(0, users.length - max);

  return (
    <div style={{ display: 'flex', alignItems: 'center' }}>
      {visible.map((u, i) => (
        <div
          key={u.id}
          title={u.name}
          style={{ ...bubble, background: colorFor(u.name), marginLeft: i === 0 ? 0 : -12 }}
        >
          {initials(u.name)}
        </div>
      ))}
      {overflow > 0 && (
        <div style={{ ...bubble, background: '#6b7280', marginLeft: -12 }} title={`${overflow} more`}>
          +{overflow}
        </div>
      )}
    </div>
  );
}

