import { Component, Input } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface User { id: number; name: string; }

@Component({
  selector: 'app-avatar-group',
  template: `
    <div style="display: flex; align-items: center;">
      <div
        *ngFor="let u of visible; let i = index"
        class="avatar"
        [title]="u.name"
        [style.background]="colorFor(u.name)"
        [style.margin-left]="i === 0 ? '0' : '-12px'"
      >{{ initials(u.name) }}</div>
      <div *ngIf="overflow > 0" class="avatar more" [title]="overflow + ' more'">+{{ overflow }}</div>
    </div>
  `,
  styles: [`
    .avatar { width: 40px; height: 40px; border-radius: 50%; border: 2px solid #fff; display: flex; align-items: center; justify-content: center; color: #fff; font-size: 14px; font-weight: 600; box-sizing: border-box; }
    .avatar.more { background: #6b7280; margin-left: -12px; }
  `],
})
export class AvatarGroupComponent {
  @Input() users: User[] = [];
  @Input() max = 4;

  private palette = ['#2563eb', '#16a34a', '#d97706', '#dc2626', '#7c3aed', '#0891b2'];

  get visible(): User[] {
    return this.users.slice(0, this.max);
  }

  get overflow(): number {
    return Math.max(0, this.users.length - this.max);
  }

  colorFor(name: string): string {
    let h = 0;
    for (let i = 0; i < name.length; i++) {
      h = (h * 31 + name.charCodeAt(i)) >>> 0;
    }
    return this.palette[h % this.palette.length];
  }

  initials(name: string): string {
    return name
      .split(' ')
      .map((w) => w[0])
      .slice(0, 2)
      .join('')
      .toUpperCase();
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Avatar Group Demo</h1>
      <app-avatar-group [users]="users" [max]="4"></app-avatar-group>
    </div>
  `,
})
export class AppComponent {
  users: User[] = [
    { id: 1, name: 'Ada Lovelace' },
    { id: 2, name: 'Alan Turing' },
    { id: 3, name: 'Grace Hopper' },
    { id: 4, name: 'Linus Torvalds' },
    { id: 5, name: 'Margaret Hamilton' },
    { id: 6, name: 'Dennis Ritchie' },
  ];
}

@NgModule({
  declarations: [AppComponent, AvatarGroupComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
